#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
from pathlib import Path
from typing import Any, Dict, Iterable, List

from dispatch_task import load_json_like, pressure_level_claude, pressure_level_openclaw
from task_runtime import (
    CONFIG_ROOT,
    QUEUE_REASONS,
    ROOT,
    LockError,
    ValidationError,
    atomic_write_json,
    handle_invalid_queue_artifact,
    load_json,
    now_iso,
    read_queue_artifact,
    sync_queue_for_task,
    task_lock,
    task_paths,
    update_state,
    write_runtime_metrics,
)

AUTH_RUNTIME_PATH = ROOT / "runtime" / "auth" / "latest-status.json"
CAPACITY_RUNTIME_PATH = ROOT / "runtime" / "capacity" / "latest-capacity.json"


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Re-evaluate queued OpenClaw tasks")
    parser.add_argument("--task-id")
    parser.add_argument("--reason", choices=list(QUEUE_REASONS))
    return parser.parse_args()


def iter_queue_entries(task_id: str | None = None, reason: str | None = None) -> Iterable[Path]:
    reasons = [reason] if reason else list(QUEUE_REASONS)
    for queue_reason in reasons:
        queue_dir = ROOT / "runtime" / "queue" / queue_reason
        if not queue_dir.exists():
            continue
        for path in sorted(queue_dir.glob("*.json")):
            if task_id and path.stem != task_id:
                continue
            yield path


def auth_recovered() -> bool:
    status = load_json(AUTH_RUNTIME_PATH, default={}) or {}
    stdout = status.get("stdout") if isinstance(status.get("stdout"), dict) else {}
    return bool(status.get("ok")) and bool(
        status.get("logged_in")
        or status.get("auth_ok")
        or stdout.get("loggedIn")
    )


def capacity_recovered(dispatch: Dict[str, Any]) -> bool:
    snapshot = load_json(CAPACITY_RUNTIME_PATH, default={}) or {}
    providers = snapshot.get("providers") if isinstance(snapshot.get("providers"), dict) else {}
    if not providers:
        return False
    policy = load_json_like(CONFIG_ROOT / "capacity-policy.yaml")
    selected_provider = str(dispatch.get("selected_provider") or "")
    if selected_provider == "claude_code":
        provider = providers.get("claude_code") or {}
        return bool(provider) and pressure_level_claude(provider, policy) == "normal"
    if selected_provider == "openclaw":
        provider = providers.get("openclaw") or {}
        return bool(provider) and pressure_level_openclaw(provider, policy) == "normal"
    openclaw = providers.get("openclaw") or {}
    claude = providers.get("claude_code") or {}
    return bool(openclaw and claude) and pressure_level_openclaw(openclaw, policy) == "normal" and pressure_level_claude(claude, policy) == "normal"


def manual_review_resolved(paths: Dict[str, Path], state: Dict[str, Any]) -> bool:
    marker = load_json(paths["manual_review_status"], default={}) or {}
    if marker.get("resolved") is True:
        return True
    if marker.get("approved") is True:
        return True
    return bool(state.get("manual_review_resolved"))


def review_can_publish(review: Dict[str, Any]) -> bool:
    return bool(review.get("publishable", review.get("publish_recommendation") == "publish")) and not bool(review.get("requires_manual_review"))


def release_waiting_auth(task_id: str, state: Dict[str, Any], route: Dict[str, Any], dispatch: Dict[str, Any], review: Dict[str, Any], now: str) -> Dict[str, Any]:
    ready_state = update_state(
        task_id,
        "READY_FOR_EXECUTION",
        route=state.get("route") or route.get("decision"),
        route_decision_id=state.get("route_decision_id") or route.get("route_decision_id"),
        approval=state.get("approval", {}),
        approval_id=state.get("approval_id"),
        dispatch_id=state.get("dispatch_id") or dispatch.get("dispatch_id"),
        message="queue rebalanced: auth recovered; ready to resume",
    )
    sync_queue_for_task(task_id, state_payload=ready_state, route=route, dispatch=dispatch, review=review, rebalanced_at=now)
    return ready_state


def release_waiting_approval(task_id: str, state: Dict[str, Any], route: Dict[str, Any], dispatch: Dict[str, Any], review: Dict[str, Any], now: str) -> Dict[str, Any]:
    ready_state = update_state(
        task_id,
        "READY_FOR_EXECUTION",
        route=state.get("route") or route.get("decision"),
        route_decision_id=state.get("route_decision_id") or route.get("route_decision_id"),
        approval=state.get("approval", {}),
        approval_id=state.get("approval_id"),
        dispatch_id=state.get("dispatch_id") or dispatch.get("dispatch_id"),
        message="queue rebalanced: approval detected; ready to resume",
    )
    sync_queue_for_task(task_id, state_payload=ready_state, route=route, dispatch=dispatch, review=review, rebalanced_at=now)
    return ready_state


def release_waiting_capacity(task_id: str, state: Dict[str, Any], route: Dict[str, Any], dispatch: Dict[str, Any], review: Dict[str, Any], now: str) -> Dict[str, Any]:
    ready_state = update_state(
        task_id,
        "READY_FOR_EXECUTION",
        route=state.get("route") or route.get("decision"),
        route_decision_id=state.get("route_decision_id") or route.get("route_decision_id"),
        approval=state.get("approval", {}),
        approval_id=state.get("approval_id"),
        dispatch_id=state.get("dispatch_id") or dispatch.get("dispatch_id"),
        message="queue rebalanced: provider capacity recovered; ready to resume",
    )
    sync_queue_for_task(task_id, state_payload=ready_state, route=route, dispatch=dispatch, review=review, rebalanced_at=now)
    return ready_state


def release_waiting_manual_review(task_id: str, state: Dict[str, Any], route: Dict[str, Any], dispatch: Dict[str, Any], review: Dict[str, Any], now: str, paths: Dict[str, Path]) -> Dict[str, Any]:
    updated_review = dict(review)
    updated_review["verdict"] = "pass"
    updated_review["publish_recommendation"] = "publish"
    updated_review["publishable"] = True
    updated_review["requires_manual_review"] = False
    updated_review["summary"] = "Manual review resolved; result may be published."
    issues = list(updated_review.get("issues", []))
    if "manual review resolved" not in issues:
        issues.append("manual review resolved")
    updated_review["issues"] = issues
    atomic_write_json(paths["review"], updated_review)

    reviewing_state = update_state(
        task_id,
        "REVIEWING",
        route=state.get("route") or route.get("decision"),
        route_decision_id=state.get("route_decision_id") or route.get("route_decision_id"),
        approval=state.get("approval", {}),
        approval_id=state.get("approval_id"),
        dispatch_id=state.get("dispatch_id") or dispatch.get("dispatch_id"),
        message="queue rebalanced: manual review resolved; ready for publish",
    )
    sync_queue_for_task(task_id, state_payload=reviewing_state, route=route, dispatch=dispatch, review=updated_review, rebalanced_at=now)
    return reviewing_state


def rebalance_one(task_id: str, expected_reason: str | None = None, artifact_path: Path | None = None) -> Dict[str, Any]:
    paths = task_paths(task_id)
    if artifact_path is not None:
        try:
            artifact = read_queue_artifact(artifact_path)
        except ValidationError as exc:
            result = handle_invalid_queue_artifact(task_id, artifact_path, f"invalid queue artifact: {artifact_path}: {exc}")
            write_runtime_metrics()
            return result
        if expected_reason and artifact.get("queue_reason") != expected_reason:
            return {"task_id": task_id, "queue_reason": expected_reason, "action": "held", "state": "mismatch"}
    try:
        with task_lock(paths["dir"]):
            state = load_json(paths["state"], default={}) or {}
            route = load_json(paths["route"], default={}) or {}
            dispatch = load_json(paths["dispatch"], default={}) or {}
            review = load_json(paths["review"], default={}) or {}
            queue_status = load_json(paths["queue_status"], default={}) or {}
            reason = expected_reason or queue_status.get("queue_reason") or queue_status.get("last_queue_reason")
            now = now_iso()
            if reason == "waiting_auth":
                if auth_recovered():
                    new_state = release_waiting_auth(task_id, state, route, dispatch, review, now)
                    write_runtime_metrics()
                    return {"task_id": task_id, "queue_reason": reason, "action": "released", "state": new_state.get("state")}
            elif reason == "waiting_approval":
                if (state.get("approval") or {}).get("approved"):
                    new_state = release_waiting_approval(task_id, state, route, dispatch, review, now)
                    write_runtime_metrics()
                    return {"task_id": task_id, "queue_reason": reason, "action": "released", "state": new_state.get("state")}
            elif reason == "waiting_capacity":
                if capacity_recovered(dispatch):
                    new_state = release_waiting_capacity(task_id, state, route, dispatch, review, now)
                    write_runtime_metrics()
                    return {"task_id": task_id, "queue_reason": reason, "action": "released", "state": new_state.get("state")}
            elif reason == "waiting_manual_review":
                if manual_review_resolved(paths, state) and not review_can_publish(review):
                    new_state = release_waiting_manual_review(task_id, state, route, dispatch, review, now, paths)
                    write_runtime_metrics()
                    return {"task_id": task_id, "queue_reason": reason, "action": "released", "state": new_state.get("state")}

            synced = sync_queue_for_task(task_id, state_payload=state, route=route, dispatch=dispatch, review=review, rebalanced_at=now)
            write_runtime_metrics()
            return {"task_id": task_id, "queue_reason": reason, "action": "held", "state": synced.get("state")}
    except LockError:
        write_runtime_metrics()
        return {"task_id": task_id, "queue_reason": expected_reason, "action": "skipped_locked", "state": "locked"}


def main() -> int:
    args = parse_args()
    results: List[Dict[str, Any]] = []
    seen: set[str] = set()
    if args.task_id:
        artifact_path = next(iter_queue_entries(task_id=args.task_id, reason=args.reason), None)
        results.append(rebalance_one(args.task_id, args.reason, artifact_path))
    else:
        for path in iter_queue_entries(reason=args.reason):
            if path.stem in seen:
                results.append({"task_id": path.stem, "queue_reason": path.parent.name, "action": "skipped_duplicate", "state": "deduped"})
                continue
            seen.add(path.stem)
            results.append(rebalance_one(path.stem, args.reason or path.parent.name, path))
    write_runtime_metrics()
    print(json.dumps({"results": results}, ensure_ascii=False, indent=2))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

def is_heavy_task(task: Dict[str, Any], intake: Dict[str, Any], assignment: Dict[str, Any]) -> bool:
    requested_paths = task.get("requested_paths", intake.get("requested_paths", []))
    text = (task.get("task") or intake.get("task_summary") or "").lower()
    return (
        intake.get("complexity") in {"high", "very_high"}
        or len(requested_paths) > 1
        or "multi-file-change" in intake.get("required_capabilities", [])
        or any(token in text for token in ["implement", "refactor", "migration", "heavy", "multi-file"])
        or len(assignment.get("active_subroles", [])) > 0
    )


def is_multi_file_write(task: Dict[str, Any], intake: Dict[str, Any]) -> bool:
    requested_paths = task.get("requested_paths", intake.get("requested_paths", []))
    text = (task.get("task") or intake.get("task_summary") or "").lower()
    if len(requested_paths) <= 1:
        return False
    read_only_markers = ["read-only", "read only", "without changing files", "no file changes"]
    return not any(marker in text for marker in read_only_markers)


def is_single_department_light(intake: Dict[str, Any], assignment: Dict[str, Any]) -> bool:
    return (
        len(intake.get("departments_involved", [])) == 1
        and intake.get("complexity") == "low"
        and intake.get("risk_level") == "low"
        and not assignment.get("active_subroles")
    )


def has_pre_auth_openclaw_value(task: Dict[str, Any], intake: Dict[str, Any], assignment: Dict[str, Any]) -> bool:
    desired_outputs = {str(item) for item in intake.get("desired_outputs", [])}
    required_capabilities = {str(item) for item in intake.get("required_capabilities", [])}
    review_focus = {str(item).lower() for item in task.get("review_focus", [])}
    constraints = " ".join(str(item) for item in task.get("constraints", []))
    return bool(
        desired_outputs.intersection({"doc", "plan", "report", "task-brief"})
        or required_capabilities.intersection({"docs", "copy", "analysis", "coordination", "requirements"})
        or any(token in constraints.lower() for token in ["context pack", "docs draft", "reviewer template"])
        or any(token in review_focus for token in ["reviewer", "documentation", "docs"])
        or len(assignment.get("advisory_subroles", [])) > 0
    )


def pressure_level_openclaw(snapshot: Dict[str, Any], policy: Dict[str, Any]) -> str:
    thresholds = policy["providers"]["openclaw"]["thresholds"]
    usage = max(float(snapshot.get("usage_pressure", 0)), float(snapshot.get("cost_pressure", 0)))
    if snapshot.get("hard_blocked") or usage >= float(thresholds["hard_pressure_at"]):
        return "hard"
    if usage >= float(thresholds["high_pressure_at"]):
        return "high"
    return "normal"


def pressure_level_claude(snapshot: Dict[str, Any], policy: Dict[str, Any]) -> str:
    thresholds = policy["providers"]["claude_code"]["thresholds"]
    pressure = max(
        float(snapshot.get("rpm_pressure", 0)),
        float(snapshot.get("itpm_pressure", 0)),
        float(snapshot.get("otpm_pressure", 0)),
        float(snapshot.get("spend_pressure", 0)),
    )
    if snapshot.get("hard_blocked") or pressure >= float(thresholds["hard_pressure_at"]):
        return "hard"
    if pressure >= float(thresholds["high_pressure_at"]) or float(snapshot.get("retry_after_sec", 0)) >= float(thresholds["retry_after_high_at"]):
        return "high"
    return "normal"


def load_lane_probe(max_age_sec: int = LANE_HEALTH_FRESHNESS_SEC) -> Tuple[Dict[str, Any], bool]:
    path = HEALTH_RUNTIME_ROOT / "lane-health.json"
    payload = load_json(path, default={}) or {}
    captured_at = payload.get("captured_at") if isinstance(payload, dict) else None
    captured_dt = None
    if captured_at:
        try:
            captured_dt = datetime.fromisoformat(str(captured_at))
        except Exception:  # noqa: BLE001
            captured_dt = None
    is_fresh = False
    if captured_dt is not None:
        is_fresh = (datetime.now(captured_dt.tzinfo or None) - captured_dt).total_seconds() <= max_age_sec
    return payload if isinstance(payload, dict) else {}, is_fresh


def lane_health_snapshot(task: Dict[str, Any], claude_snapshot: Dict[str, Any]) -> Dict[str, Any]:
    metrics = load_json(ROOT / "runtime" / "metrics" / "latest-metrics.json", default={}) or {}
    probe_payload, probe_fresh = load_lane_probe()
    probe_lanes = probe_payload.get("lanes") if isinstance(probe_payload.get("lanes"), dict) else {}
    auth_payload = probe_payload.get("auth") if isinstance(probe_payload.get("auth"), dict) else {}

    auth_ok = bool(claude_snapshot.get("auth_ok", True))
    acp_healthy = bool(claude_snapshot.get("acp_healthy", claude_snapshot.get("healthy", False)))
    cli_healthy = bool(claude_snapshot.get("cli_healthy", claude_snapshot.get("healthy", False)))
    cli_backend_healthy = bool(claude_snapshot.get("cli_backend_healthy", cli_healthy))
    lane_errors: Dict[str, Any] = {}
    lane_latencies: Dict[str, Any] = {}
    probe_transport: Dict[str, Any] = {}

    if probe_fresh and str(claude_snapshot.get("source") or "") != "test":
        auth_ok = bool(auth_payload.get("auth_ok", auth_ok))
        acp = probe_lanes.get("acp") if isinstance(probe_lanes.get("acp"), dict) else {}
        cli = probe_lanes.get("cli") if isinstance(probe_lanes.get("cli"), dict) else {}
        cli_backend = probe_lanes.get("cli_backend_safety_net") if isinstance(probe_lanes.get("cli_backend_safety_net"), dict) else {}
        acp_healthy = bool(acp.get("healthy", acp_healthy))
        cli_healthy = bool(cli.get("healthy", cli_healthy))
        cli_backend_healthy = bool(cli_backend.get("healthy", cli_backend_healthy))
        lane_errors = {
            "acp": acp.get("last_error"),
            "cli": cli.get("last_error"),
            "cli_backend_safety_net": cli_backend.get("last_error"),
        }
        lane_latencies = {
            "acp": acp.get("latency_ms"),
            "cli": cli.get("latency_ms"),
            "cli_backend_safety_net": cli_backend.get("latency_ms"),
        }
        probe_transport = {
            "acp": acp.get("transport_kind"),
            "cli": cli.get("transport_kind"),
            "cli_backend_safety_net": cli_backend.get("transport_kind"),
        }

    return {
        "auth_ok": auth_ok,
        "acp_healthy": acp_healthy,
        "cli_healthy": cli_healthy,
        "cli_backend_healthy": cli_backend_healthy,
        "acp_last_success_at": metrics.get("acp_last_success_at"),
        "cli_last_success_at": metrics.get("cli_last_success_at"),
        "acp_consecutive_failures": int(metrics.get("acp_consecutive_failures", 0) or 0),
        "cli_consecutive_failures": int(metrics.get("cli_consecutive_failures", 0) or 0),
        "retry_after_sec": float(claude_snapshot.get("retry_after_sec", 0) or 0),
        "hard_blocked": bool(claude_snapshot.get("hard_blocked", False)),
        "probe_fresh": probe_fresh,
        "probe_path": str((HEALTH_RUNTIME_ROOT / "lane-health.json").relative_to(ROOT.parent)),
        "lane_last_error": lane_errors,
        "lane_latency_ms": lane_latencies,
        "lane_transport": probe_transport,
        "captured_at": (probe_payload.get("captured_at") if probe_fresh else claude_snapshot.get("captured_at")) or now_iso(),
    }


def fallback_chain_for_primary_mode(primary_mode: str) -> List[str]:
    if primary_mode == "cli":
        return ["cli", "cli_backend_safety_net"]
    return ["acp", "cli", "cli_backend_safety_net"]


def select_claude_lane(task: Dict[str, Any], claude_snapshot: Dict[str, Any]) -> Tuple[str, List[str], List[str], Dict[str, Any], str | None]:
    config = load_claude_code_config()
    primary_mode = str(config.get("primary_mode") or "acp")
    fallback_chain = fallback_chain_for_primary_mode(primary_mode)
    health = lane_health_snapshot(task, claude_snapshot)
    reasons: List[str] = [f"primary_mode={primary_mode}"]
    if not health["auth_ok"]:
        reasons.append("claude auth unavailable")
        return "none", reasons, fallback_chain, health, "waiting_auth"

    for lane in fallback_chain:
        healthy_key = {
            "acp": "acp_healthy",
            "cli": "cli_healthy",
            "cli_backend_safety_net": "cli_backend_healthy",
        }[lane]
        if health.get(healthy_key):
            reasons.append(f"selected {lane} because {healthy_key}=true")
            return lane, reasons, fallback_chain, health, None
        reasons.append(f"skip {lane} because {healthy_key}=false")

    reasons.append("no Claude lane healthy")
    return "none", reasons, fallback_chain, health, "waiting_capacity"


def role_provider_preference(role_name: str) -> List[str]:
    role_caps = load_json_like(CONFIG_ROOT / "role-capability.yaml")
    role = (role_caps.get("roles") or {}).get(role_name, {})
    prefs = role.get("default_provider_preference") or ["openclaw", "claude-code"]
    normalized: List[str] = []
    for item in prefs:
        if item == "claude-code":
            normalized.append("claude_code")
        else:
            normalized.append(str(item))
    return normalized


